const config = $('Set RSS Source').first().json;
const xml = String($json.data ?? $json.body ?? $json.response ?? $json ?? '');

function decode(value) {
  return String(value ?? '')
    .replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1')
    .replace(/&amp;/g, '&')
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&quot;/g, '"')
    .replace(/&#39;/g, "'")
    .trim();
}

function stripHtml(value) {
  return decode(value)
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<[^>]+>/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

function tag(block, name) {
  const match = block.match(new RegExp(`<${name}[^>]*>([\\s\\S]*?)<\\/${name}>`, 'i'));
  return match ? decode(match[1]) : '';
}

const itemBlocks = xml.match(/<item[\s\S]*?<\/item>/gi) ?? [];
const entryBlocks = xml.match(/<entry[\s\S]*?<\/entry>/gi) ?? [];
const blocks = itemBlocks.length ? itemBlocks : entryBlocks;
const maxItems = Number(config.maxItems ?? 1);

return blocks.slice(0, maxItems).map((block) => {
  const isAtom = /<entry[\s\S]*?<\/entry>/i.test(block);
  const title = stripHtml(tag(block, 'title'));
  const description = stripHtml(tag(block, 'description') || tag(block, 'summary') || tag(block, 'content'));
  const rssLink = stripHtml(tag(block, 'link'));
  const atomLinkMatch = block.match(/<link[^>]+href=["']([^"']+)["'][^>]*>/i);
  const sourceUrl = isAtom ? decode(atomLinkMatch?.[1] ?? rssLink) : rssLink;
  const publishedRaw = tag(block, 'pubDate') || tag(block, 'published') || tag(block, 'updated');
  const publishedAt = Number.isNaN(new Date(publishedRaw).getTime()) ? new Date().toISOString() : new Date(publishedRaw).toISOString();

  return {
    json: {
      ingestApiUrl: config.ingestApiUrl,
      aiNewsIngestSecret: config.aiNewsIngestSecret,
      title,
      summary: description || `${title} 的最新 AI 情報更新。`,
      content: description || `${title} 的 RSS 來源未提供完整內文，請查看原始來源。`,
      category: '開源專案',
      source: config.source,
      source_url: sourceUrl,
      image_url: '',
      published_at: publishedAt,
      importance_score: 60,
      is_breaking: false,
      tags: ['Hugging Face', 'AI 情報', 'RSS']
    }
  };
}).filter((item) => item.json.title && item.json.source_url);

return items.map((item) => {
  const result = item.json;
  return {
    json: {
      ok: result.ok === true,
      duplicated: result.duplicated === true,
      id: result.id ?? null,
      url: result.url ?? null,
      message: result.message ?? null,
      details: result.details ?? null,
      hint: result.hint ?? null,
      code: result.code ?? null,
      nextStep: result.ok === true && result.id ? `確認文章：http://localhost:3000/news/${result.id}` : '檢查 API URL、AI_NEWS_INGEST_SECRET 或錯誤訊息。'
    }
  };
});
